code_after:
# Secrets Manager module with idempotent create/import behavior
#
# The lifecycle.prevent_destroy ensures secrets are not accidentally deleted.
# Use import blocks in the root module to bring pre-existing secrets into state.
# The create_before_destroy ensures smooth transitions during secret renames.

resource "aws_secretsmanager_secret" "this" {
  name                    = "cryptogate/${var.environment}/${var.secret_name}"
  description             = var.description
  kms_key_id              = var.kms_key_id
  recovery_window_in_days = var.recovery_window_in_days

  tags = {
    Environment = var.environment
  }

  lifecycle {
    # Prevent accidental deletion of secrets
    prevent_destroy = true
    # Allow smooth renames by creating new before destroying old
    create_before_destroy = true
  }
}

resource "aws_secretsmanager_secret_version" "initial" {
  secret_id     = aws_secretsmanager_secret.this.id
  secret_string = var.initial_value

  lifecycle {
    ignore_changes = [secret_string]
  }
}

