  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_versioning" "frontend" {
  for_each = local.frontends
  bucket   = aws_s3_bucket.frontend[each.key].id
