# Stolink Shared Environment - Main Configuration
# Resources that are shared across dev and prod environments

terraform {
  required_version = ">= 1.5.0"

  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }

  # Uncomment to use remote state
  # backend "s3" {
  #   bucket         = "stolink-terraform-state"
  #   key            = "shared/terraform.tfstate"
  #   region         = "ap-northeast-2"
  #   encrypt        = true
  #   dynamodb_table = "terraform-state-lock"
  # }
}

provider "aws" {
  region = "ap-northeast-2"

  default_tags {
    tags = {
      Environment = "shared"
      ManagedBy   = "Terraform"
      Project     = "stolink"
    }
  }
}

#######################################
# ECR Module (Shared across environments)
#######################################
# ECR repositories are shared between dev and prod
# Images are tagged differently: dev, release, latest
module "ecr" {
  source = "../../modules/ecr"

  repository_names = [
    "stolink/stolink-spring",
    "stolink/storead-spring",
    "stolink/stolink-fastapi-agent",
    "stolink/stolink-fastapi-image",
    "stolink/stolink-chat"
  ]

  tags = {
    Name = "stolink-ecr"
  }
}

#######################################
# S3 Bucket for Terraform Secrets
#######################################
# Stores sensitive terraform.tfvars files
# - Versioning enabled for recovery
# - Server-side encryption (AES256)
# - Public access blocked
resource "aws_s3_bucket" "terraform_secrets" {
  bucket = "stolink-terraform-secrets"

  tags = {
    Name        = "stolink-terraform-secrets"
    Description = "Terraform tfvars backup storage"
  }
}

resource "aws_s3_bucket_versioning" "terraform_secrets" {
  bucket = aws_s3_bucket.terraform_secrets.id

  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "terraform_secrets" {
  bucket = aws_s3_bucket.terraform_secrets.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "terraform_secrets" {
  bucket = aws_s3_bucket.terraform_secrets.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Optional: Delete old versions after 90 days to save storage costs
resource "aws_s3_bucket_lifecycle_configuration" "terraform_secrets" {
  bucket = aws_s3_bucket.terraform_secrets.id

  rule {
    id     = "delete-old-versions"
    status = "Enabled"

    filter {}  # Apply to all objects

    noncurrent_version_expiration {
      noncurrent_days = 90
    }
  }
}

